const body = $input.first().json.body || $input.first().json;
const eventType = body.message?.type || body.type || '';

// Only process end-of-call-report
if (eventType !== 'end-of-call-report') {
  return [{ json: { skip: true, eventType } }];
}

const message = body.message || body;
const callData = message.call || {};
const artifact = message.artifact || {};
const analysis = message.analysis || {};

// Transcript
const transcript = artifact.transcript ||
                   message.transcript ||
                   'No transcript available';
const t = transcript.toLowerCase();

// --- DURATION CALCULATION (BULLETPROOF) ---
let duration = 'N/A';
try {
  // Search for start time in all possible VAPI locations
  const startStr = callData.startedAt || callData.createdAt || message.startedAt || message.createdAt;

  // Search for end time in all possible VAPI locations
  const endStr = callData.endedAt || message.endedAt;

  if (startStr && endStr) {
    const startMs = new Date(startStr).getTime();
    const endMs = new Date(endStr).getTime();
    const secs = Math.round((endMs - startMs) / 1000);

    // Only set duration if we got a valid number greater than 0
    if (!isNaN(secs) && secs >= 0) {
      duration = `${Math.floor(secs / 60)}m ${secs % 60}s`;
    }
  }
} catch(e) { 
  duration = 'Calc Error'; 
}

// Core fields
const endedReason = callData.endedReason || message.endedReason || 'Unknown';
const recordingUrl = artifact.recordingUrl || artifact.stereoRecordingUrl || 'Not available';
const summary = analysis.summary || '';

// --- EXTRACT PATIENT DETAILS FROM TRANSCRIPT ---

// Patient Name
let patientName = 'Unknown';
const namePatterns = [
  /my name is ([A-Za-z\s]+)/i,
  /i(?:'m| am) ([A-Za-z\s]+)/i,
  /this is ([A-Za-z\s]+)/i,
  /name(?:'s| is) ([A-Za-z\s]+)/i,
  /call me ([A-Za-z\s]+)/i
];
for (const pattern of namePatterns) {
  const match = transcript.match(pattern);
  if (match) {
    patientName = match[1].trim().split(/\s+/).slice(0, 2).join(' ');
    patientName = patientName.replace(/[^a-zA-Z\s]/g, '').trim();
    if (patientName.length > 2) break;
  }
}

// Patient type
let patientType = 'Unknown';
if (t.includes('new patient') || t.includes('first time') || t.includes('never been')) {
  patientType = 'New Patient';
} else if (t.includes('existing') || t.includes('been before') || t.includes('visited before') || t.includes('came before')) {
  patientType = 'Existing Patient';
}

// Reason for visit
let reasonForVisit = 'General Checkup';
if (t.includes('whitening') || t.includes('whiten')) {
  reasonForVisit = 'Teeth Whitening';
} else if (t.includes('root canal')) {
  reasonForVisit = 'Root Canal';
} else if (t.includes('filling') || t.includes('cavity') || t.includes('cavities')) {
  reasonForVisit = 'Filling / Cavity';
} else if (t.includes('extraction') || t.includes('remove') || t.includes('pull out')) {
  reasonForVisit = 'Tooth Extraction';
} else if (t.includes('orthodon') || t.includes('braces') || t.includes('aligners')) {
  reasonForVisit = 'Orthodontics Consultation';
} else if (t.includes('emergency') || t.includes('severe pain') || t.includes('swelling') || t.includes('broken')) {
  reasonForVisit = 'Emergency';
} else if (t.includes('checkup') || t.includes('cleaning') || t.includes('routine')) {
  reasonForVisit = 'General Checkup & Cleaning';
}

// Booking status
let bookingStatus = 'Incomplete';
if (t.includes('cancel')) {
  bookingStatus = 'Cancelled';
} else if (t.includes('reschedule')) {
  bookingStatus = 'Rescheduled';
} else (
  t.includes('booked') ||
  t.includes('scheduled') ||
  t.includes("we'll see you") ||
  t.includes('see you then') ||
  t.includes('confirmed') ||
  t.includes('appointment is set') ||
  t.includes('look forward to seeing you')
) {
  bookingStatus = 'Booked';
}

// Emergency flag
const isEmergency = reasonForVisit === 'Emergency';

// Raw date/time text for Gemini
let rawDateTimeText = '';
const dateKeywords = ['monday','tuesday','wednesday','thursday','friday','saturday','sunday',
  'today','tomorrow','morning','afternoon','evening','am','pm',
  'january','february','march','april','may','june','july','august',
  'september','october','november','december','next week','this week',
  'o\'clock','at ','on '];

const sentences = transcript.split(/[.!?]/);
for (const sentence of sentences) {
  if (dateKeywords.some(k => sentence.toLowerCase().includes(k))) {
    rawDateTimeText += sentence.trim() + '. ';
  }
}
rawDateTimeText = rawDateTimeText.trim() || 'No specific date/time mentioned';

return [{
  json: {
    skip: false,
    timestamp: new Date().toLocaleString('en-PK', { timeZone: 'Asia/Karachi' }),
    patientName,
    patientType,
    reasonForVisit,
    bookingStatus,
    isEmergency,
    rawDateTimeText,
    callDuration: duration,
    endedReason,
    summary,
    fullTranscript: transcript,
    recordingUrl
  }
}];

