const prevData = $input.first().json;
const rawDateTimeText = prevData.rawDateTimeText || 'No date mentioned';
const GEMINI_API_KEY = 'YOUR_GEMINI_API_KEY_HERE';
const today = new Date().toISOString();

const requestBody = {
  system_instruction: {
    parts: [{
      text: `You extract appointment date and time from natural language. Today is ${today}. Return ONLY a JSON object with this exact structure: {"appointmentStart": "2026-06-27T10:00:00", "appointmentEnd": "2026-06-27T10:30:00", "readableDateTime": "Friday 27 June at 10:00 AM", "confidence": "high"}. If no specific date found, use tomorrow at 10am and set confidence to low. Appointments are 30 minutes long.`
    }]
  },
  contents: [{
    role: 'user',
    parts: [{
      text: `Extract appointment date and time from: ${rawDateTimeText}`
    }]
  }],
  generationConfig: {
    response_mime_type: 'application/json'
  }
};

let parsedDate = {};
try {
  const response = await $http.request({
    method: 'POST',
    url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent`,
    headers: {
      'Content-Type': 'application/json',
      'x-goog-api-key': GEMINI_API_KEY
    },
    body: requestBody,
    json: true
  });

  const content = response.candidates[0].content.parts[0].text;
  parsedDate = JSON.parse(content);
} catch(e) {
  // Fallback: tomorrow at 10am
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  tomorrow.setHours(10, 0, 0, 0);
  const end = new Date(tomorrow);
  end.setMinutes(end.getMinutes() + 30);
  parsedDate = {
    appointmentStart: tomorrow.toISOString(),
    appointmentEnd: end.toISOString(),
    readableDateTime: 'Tomorrow at 10:00 AM',
    confidence: 'low'
  };
}

return [{
  json: {
    ...prevData,
    appointmentStart: parsedDate.appointmentStart,
    appointmentEnd: parsedDate.appointmentEnd,
    readableDateTime: parsedDate.readableDateTime || 'Not parsed',
    dateConfidence: parsedDate.confidence || 'low'
  }
}];
